    sep #$20
    .a8
    lda #$01
    sta f:$7EE010
    jmp test_restore
@fail1:
    ; D was not cleared on interrupt entry
    sep #$20
    .a8
    lda #$02
    sta f:$7EE010
    jmp test_restore
.endproc

