; A6.05 — Native pushes 4 bytes
; provenance: Documented (WDC datasheet)
.proc test_a6_05
    .a16
    .i16
    jmp @start
@handler:
    rep #$30
    .a16
    .i16
    tsc
    sta f:$7E0094     ; stack pointer as seen inside the handler
    rti
@start:
    rep #$30
    .a16
    .i16
    lda #.LOWORD(@handler)
    sta a:V_BRK_VEC
    tsc
    sta f:$7E0096     ; stack pointer before the interrupt
    brk
    .byte $EA
    rep #$30
    .a16
    .i16
    lda f:$7E0096
    sec
    sbc f:$7E0094
    cmp #$0004
    beq :+
    jmp @fail1
